import java.util.Scanner;

public class SafeBufferExample {

    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);

        System.out.print("Enter a string: ");
        String input = scanner.nextLine();

        // Ensure that the buffer size matches or exceeds the input length to prevent buffer overflow
        char[] buffer = new char[input.length()];

        // Copy characters from user input into the buffer array safely
        for (int i = 0; i < input.length(); i++) {
            if (i < buffer.length) {
                buffer[i] = input.charAt(i);
            } else {
                break; // Stop copying if we reach the end of the buffer
            }
        }

        System.out.println("Input copied into buffer safely.");
    }
}

